"""
Regression test for Qt 6.4 dark mode text threshold setting bug.

This test verifies that the 'threshold.text' setting is correctly mapped to
'ForegroundBrightnessThreshold' (instead of 'TextBrightnessThreshold') when
using Qt 6.4.

The bug: In Qt 6.4, Chromium renamed the TextBrightnessThreshold setting to
ForegroundBrightnessThreshold. If qutebrowser continues to use the old name
on Qt 6.4, the setting will be silently ignored by Chromium, resulting in
no effect on dark mode rendering.
"""

import sys
import copy
import dataclasses
import collections
from typing import Any, Iterator, Mapping, Optional, Set, Tuple, Union, Sequence, List


@dataclasses.dataclass
class _Setting:
    """A single dark mode setting."""
    option: str
    chromium_key: str
    mapping: Optional[Mapping[Any, Union[str, int]]] = None

    def _value_str(self, value: Any) -> str:
        if self.mapping is None:
            return str(value)
        return str(self.mapping[value])

    def chromium_tuple(self, value: Any) -> Tuple[str, str]:
        return self.chromium_key, self._value_str(value)

    def with_prefix(self, prefix: str) -> '_Setting':
        return _Setting(
            option=self.option,
            chromium_key=prefix + self.chromium_key,
            mapping=self.mapping,
        )


class _Definition:
    """A collection of dark mode setting names for the given QtWebEngine version."""

    def __init__(
            self,
            *args: _Setting,
            mandatory: Set[str],
            prefix: str,
            switch_names: Mapping[Optional[str], str] = None,
    ) -> None:
        self._settings = args
        self.mandatory = mandatory
        self.prefix = prefix
        if switch_names is not None:
            self._switch_names = switch_names
        else:
            self._switch_names = {None: 'blink-settings'}

    def prefixed_settings(self) -> Iterator[Tuple[str, _Setting]]:
        """Get all "prepared" settings."""
        for setting in self._settings:
            switch = self._switch_names.get(setting.option, self._switch_names[None])
            yield switch, setting.with_prefix(self.prefix)

    def copy_add_setting(self, setting: _Setting) -> '_Definition':
        """Get a new _Definition object with an additional setting."""
        new = copy.copy(self)
        new._settings = self._settings + (setting,)
        return new

    def copy_replace_setting(self, option: str, chromium_key: str) -> '_Definition':
        """Get a new _Definition object with a setting's chromium_key replaced."""
        new = copy.deepcopy(self)
        for setting in new._settings:
            if setting.option == option:
                setting.chromium_key = chromium_key
                return new
        raise ValueError(f"Setting {option} not found in {self}")


# Define the mappings for algorithms and policies
_ALGORITHMS_NEW = {
    'brightness-rgb': 1,
    'lightness-hsl': 2,
    'lightness-cielab': 3,
}

_IMAGE_POLICIES = {
    'always': 0,
    'never': 1,
    'smart': 2,
}

_INT_BOOLS = {
    True: '1',
    False: '0',
}


# Create the definitions exactly as in the actual code
_DEFINITIONS = {
    'qt_515_3': _Definition(
        _Setting('enabled', 'forceDarkModeEnabled'),
        _Setting('algorithm', 'InversionAlgorithm', _ALGORITHMS_NEW),
        _Setting('policy.images', 'ImagePolicy', _IMAGE_POLICIES),
        _Setting('contrast', 'ContrastPercent'),
        _Setting('grayscale.all', 'IsGrayScale'),
        _Setting('threshold.text', 'TextBrightnessThreshold'),
        _Setting('threshold.background', 'BackgroundBrightnessThreshold'),
        _Setting('grayscale.images', 'ImageGrayScalePercent'),
        mandatory={'enabled', 'policy.images'},
        prefix='',
        switch_names={'enabled': 'blink-settings', None: 'dark-mode-settings'},
    ),
}

# Qt 6.3 is Qt 5.15.3 with an additional setting
_DEFINITIONS['qt_63'] = _DEFINITIONS['qt_515_3'].copy_add_setting(
    _Setting('increase_text_contrast', 'IncreaseTextContrast', _INT_BOOLS),
)

# Qt 6.4 should be Qt 6.3 with threshold.text renamed to ForegroundBrightnessThreshold
_DEFINITIONS['qt_64'] = _DEFINITIONS['qt_63'].copy_replace_setting(
    'threshold.text', 'ForegroundBrightnessThreshold',
)


def test_qt64_threshold_text_is_renamed():
    """Test that Qt 6.4 uses ForegroundBrightnessThreshold instead of TextBrightnessThreshold."""
    # For Qt 5.15.3, the threshold.text should map to 'TextBrightnessThreshold'
    qt515_3_def = _DEFINITIONS['qt_515_3']
    threshold_text_qt515_3 = None
    for _, setting in qt515_3_def.prefixed_settings():
        if setting.option == 'threshold.text':
            threshold_text_qt515_3 = setting.chromium_key
            break

    assert threshold_text_qt515_3 == 'TextBrightnessThreshold', (
        f"Qt 5.15.3 should use TextBrightnessThreshold, but got {threshold_text_qt515_3}"
    )

    # For Qt 6.4, the threshold.text should map to 'ForegroundBrightnessThreshold'
    qt64_def = _DEFINITIONS['qt_64']
    threshold_text_qt64 = None
    for _, setting in qt64_def.prefixed_settings():
        if setting.option == 'threshold.text':
            threshold_text_qt64 = setting.chromium_key
            break

    assert threshold_text_qt64 == 'ForegroundBrightnessThreshold', (
        f"Qt 6.4 should use ForegroundBrightnessThreshold, but got {threshold_text_qt64}. "
        f"This is the bug: the setting name was not updated for Qt 6.4, so Chromium "
        f"will ignore it (it only recognizes ForegroundBrightnessThreshold in Qt 6.4)."
    )

    print("✓ Qt 5.15.3 correctly uses TextBrightnessThreshold")
    print("✓ Qt 6.4 correctly uses ForegroundBrightnessThreshold")


def test_qt64_other_settings_unchanged():
    """Verify that other settings remain unchanged when renaming threshold.text."""
    qt63_def = _DEFINITIONS['qt_63']
    qt64_def = _DEFINITIONS['qt_64']

    # Get all settings (excluding threshold.text) from both definitions
    qt63_settings = {}
    qt64_settings = {}

    for _, setting in qt63_def.prefixed_settings():
        if setting.option != 'threshold.text':
            qt63_settings[setting.option] = setting.chromium_key

    for _, setting in qt64_def.prefixed_settings():
        if setting.option != 'threshold.text':
            qt64_settings[setting.option] = setting.chromium_key

    # All non-threshold.text settings should remain the same
    for option in qt63_settings:
        assert qt63_settings[option] == qt64_settings.get(option), (
            f"Qt 6.4 should not change {option} setting "
            f"(Qt 6.3: {qt63_settings[option]}, Qt 6.4: {qt64_settings.get(option)})"
        )

    print("✓ All other settings correctly unchanged between Qt 6.3 and Qt 6.4")


def test_qt64_background_threshold_unchanged():
    """Verify that background threshold is not affected (only text threshold changed)."""
    qt64_def = _DEFINITIONS['qt_64']

    background_threshold_key = None
    for _, setting in qt64_def.prefixed_settings():
        if setting.option == 'threshold.background':
            background_threshold_key = setting.chromium_key
            break

    assert background_threshold_key == 'BackgroundBrightnessThreshold', (
        f"Qt 6.4 background threshold should still be BackgroundBrightnessThreshold, "
        f"but got {background_threshold_key}"
    )

    print("✓ Background threshold correctly remains BackgroundBrightnessThreshold in Qt 6.4")


def test_qt64_has_increase_text_contrast():
    """Verify that Qt 6.4 still has the IncreaseTextContrast setting from Qt 6.3."""
    qt64_def = _DEFINITIONS['qt_64']

    increase_text_contrast_found = False
    for _, setting in qt64_def.prefixed_settings():
        if setting.option == 'increase_text_contrast':
            increase_text_contrast_found = True
            assert setting.chromium_key == 'IncreaseTextContrast'
            break

    assert increase_text_contrast_found, (
        "Qt 6.4 should inherit IncreaseTextContrast from Qt 6.3"
    )

    print("✓ Qt 6.4 correctly inherits IncreaseTextContrast from Qt 6.3")


if __name__ == '__main__':
    print("Running regression tests for Qt 6.4 dark mode threshold.text setting...\n")

    try:
        test_qt64_threshold_text_is_renamed()
        print()
        test_qt64_other_settings_unchanged()
        print()
        test_qt64_background_threshold_unchanged()
        print()
        test_qt64_has_increase_text_contrast()
        print("\n" + "=" * 70)
        print("All regression tests passed!")
        print("=" * 70)
    except AssertionError as e:
        print(f"\n❌ Test failed: {e}")
        sys.exit(1)

