    """Test that Qt 6.4 uses ForegroundBrightnessThreshold instead of TextBrightnessThreshold."""
    # For Qt 5.15.3, the threshold.text should map to 'TextBrightnessThreshold'
    qt515_3_def = _DEFINITIONS['qt_515_3']
    threshold_text_qt515_3 = None
    for _, setting in qt515_3_def.prefixed_settings():
        if setting.option == 'threshold.text':
            threshold_text_qt515_3 = setting.chromium_key
            break

    assert threshold_text_qt515_3 == 'TextBrightnessThreshold', (
        f"Qt 5.15.3 should use TextBrightnessThreshold, but got {threshold_text_qt515_3}"
    )

    # For Qt 6.4, the threshold.text should map to 'ForegroundBrightnessThreshold'
    qt64_def = _DEFINITIONS['qt_64']
    threshold_text_qt64 = None
    for _, setting in qt64_def.prefixed_settings():
        if setting.option == 'threshold.text':
            threshold_text_qt64 = setting.chromium_key
            break

    assert threshold_text_qt64 == 'ForegroundBrightnessThreshold', (
        f"Qt 6.4 should use ForegroundBrightnessThreshold, but got {threshold_text_qt64}. "
        f"This is the bug: the setting name was not updated for Qt 6.4, so Chromium "
        f"will ignore it (it only recognizes ForegroundBrightnessThreshold in Qt 6.4)."
    )

    print("✓ Qt 5.15.3 correctly uses TextBrightnessThreshold")
    print("✓ Qt 6.4 correctly uses ForegroundBrightnessThreshold")


def test_qt64_other_settings_unchanged():
    """Verify that other settings remain unchanged when renaming threshold.text."""
    qt63_def = _DEFINITIONS['qt_63']
    qt64_def = _DEFINITIONS['qt_64']

    # Get all settings (excluding threshold.text) from both definitions
    qt63_settings = {}
    qt64_settings = {}

    for _, setting in qt63_def.prefixed_settings():
        if setting.option != 'threshold.text':
            qt63_settings[setting.option] = setting.chromium_key

    for _, setting in qt64_def.prefixed_settings():
        if setting.option != 'threshold.text':
            qt64_settings[setting.option] = setting.chromium_key

    # All non-threshold.text settings should remain the same
    for option in qt63_settings:
        assert qt63_settings[option] == qt64_settings.get(option), (
            f"Qt 6.4 should not change {option} setting "
            f"(Qt 6.3: {qt63_settings[option]}, Qt 6.4: {qt64_settings.get(option)})"
        )

    print("✓ All other settings correctly unchanged between Qt 6.3 and Qt 6.4")


def test_qt64_background_threshold_unchanged():
    """Verify that background threshold is not affected (only text threshold changed)."""
    qt64_def = _DEFINITIONS['qt_64']

    background_threshold_key = None
    for _, setting in qt64_def.prefixed_settings():
        if setting.option == 'threshold.background':
            background_threshold_key = setting.chromium_key
            break

    assert background_threshold_key == 'BackgroundBrightnessThreshold', (
        f"Qt 6.4 background threshold should still be BackgroundBrightnessThreshold, "
        f"but got {background_threshold_key}"
    )

    print("✓ Background threshold correctly remains BackgroundBrightnessThreshold in Qt 6.4")


def test_qt64_has_increase_text_contrast():
    """Verify that Qt 6.4 still has the IncreaseTextContrast setting from Qt 6.3."""
    qt64_def = _DEFINITIONS['qt_64']

    increase_text_contrast_found = False
    for _, setting in qt64_def.prefixed_settings():
        if setting.option == 'increase_text_contrast':
            increase_text_contrast_found = True
            assert setting.chromium_key == 'IncreaseTextContrast'
            break

    assert increase_text_contrast_found, (
        "Qt 6.4 should inherit IncreaseTextContrast from Qt 6.3"
    )

    print("✓ Qt 6.4 correctly inherits IncreaseTextContrast from Qt 6.3")


if __name__ == '__main__':
    print("Running regression tests for Qt 6.4 dark mode threshold.text setting...\n")

    try:
        test_qt64_threshold_text_is_renamed()
        print()
        test_qt64_other_settings_unchanged()
        print()
        test_qt64_background_threshold_unchanged()
        print()
        test_qt64_has_increase_text_contrast()
        print("\n" + "=" * 70)
        print("All regression tests passed!")
        print("=" * 70)
    except AssertionError as e:
        print(f"\n❌ Test failed: {e}")
        sys.exit(1)

